539→@Composable
540→fun DictationPanel(
541→    subtitle: SubtitleCue?,
542→    onSpeak: (String) -> Unit,
543→    onNext: () -> Unit,
544→    onLookup: (String) -> Unit
545→) {
546→    if (subtitle == null) {
547→        Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
548→            Text("没有字幕可用", color = MaterialTheme.colorScheme.onSurfaceVariant)
549→        }
550→        return
551→    }
552→
553→    val words = subtitle.text.split(Regex("\\s+")).filter { it.isNotBlank() }
554→    val answers = remember(subtitle) { words.map { it.replace(Regex("[^\\p{L}\\p{M}'-]"), "") } }
555→    val inputs = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
556→    val results = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
557→
558→    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
559→        // Word input boxes
560→        Card(modifier = Modifier.fillMaxWidth()) {
561→            Column(modifier = Modifier.padding(16.dp)) {
562→                Row(
563→                    modifier = Modifier.fillMaxWidth(),
564→                    horizontalArrangement = Arrangement.spacedBy(8.dp),
565→                    verticalAlignment = Alignment.CenterVertically
566→                ) {
567→                    words.forEachIndexed { i, word ->
568→                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
569→                            OutlinedTextField(
570→                                value = inputs[i],
571→                                onValueChange = { inputs[i] = it },
